import React from 'react';
import TheaterBooking from './components/TheaterBooking';
import './App.css';

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>Theater Booking System</h1>
      </header>
      <main>
        <TheaterBooking />
      </main>
    </div>
  );
}

export default App;
